102|    /** 修复 role 交替违规——防止 USER→USER 连续导致 API 截断返回空文本 */
103|    public void fixRoleAlternation() {
104|        if (history.size() < 2) return;
105|        for (int i = 1; i < history.size(); i++) {
106|            Role prev = history.get(i - 1).role();
107|            Role curr = history.get(i).role();
108|            if (prev == Role.USER && curr == Role.USER) {
109|                // 合并两条连续 USER 消息，而非插入无意义的占位消息
110|                MessageRecord a = history.get(i - 1);
111|                MessageRecord b = history.get(i);
112|                String mergedContent = joinContent(a.content(), b.content());
113|                List<MessageBlock> mergedBlocks = new ArrayList<>(a.blocks());
114|                mergedBlocks.addAll(b.blocks());
115|                history.set(i - 1, new MessageRecord(Role.USER, mergedContent, mergedBlocks));
116|                history.remove(i);
117|                i--; // 重新检查当前位置
118|            } else if (prev == Role.ASSISTANT && curr == Role.ASSISTANT) {
119|                MessageRecord a = history.get(i - 1);
120|                MessageRecord b = history.get(i);
121|                String mergedContent = joinContent(a.content(), b.content());
122|                List<MessageBlock> mergedBlocks = new ArrayList<>(a.blocks());
123|                mergedBlocks.addAll(b.blocks());
124|                history.set(i - 1, new MessageRecord(Role.ASSISTANT, mergedContent, mergedBlocks));
125|                history.remove(i);
126|                i--;
127|            }
128|        }
129|    }
